package dev.harrison.rendacomcarro.operation.domain;
import jakarta.persistence.*; import java.math.BigDecimal; import java.time.LocalDateTime; import java.util.UUID;
@Entity @Table(name="trip") public class Trip { @Id private UUID id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="shift_id",nullable=false) private Shift shift; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="platform_id") private Platform platform; @Column(name="started_at") private LocalDateTime startedAt; @Column(name="ended_at") private LocalDateTime endedAt; @Column(name="gross_amount") private BigDecimal grossAmount; @Column(name="net_amount") private BigDecimal netAmount; private BigDecimal distance; @Enumerated(EnumType.STRING) private DataSource source; @Column(name="external_reference") private String externalReference; protected Trip(){} public UUID getId(){return id;} }
